import { Component, computed, inject, OnDestroy } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { MatFormFieldModule, MatLabel } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatInputModule } from '@angular/material/input';
import { MatTableDataSource, MatTableModule } from '@angular/material/table';
import { MatDialog, MatDialogConfig } from '@angular/material/dialog';
import { SnackbarService } from '../../../shared/snack-bar/snack-bar.service';
import { LoaderComponent } from '../../../shared/loader/loader.component';
import { LoaderService } from '../../../shared/loader/loader.service';
import { MaPurpose } from './purpose.model';
import { PurposeService } from './purpose.service';
import { CreatePurposeComponent } from '../../../components/create-purpose/create-purpose.component';
import { Subject } from 'rxjs';
import { debounceTime} from 'rxjs/operators';

@Component({
  selector: 'app-purpose',
  standalone: true,
  imports: [
    MatFormFieldModule, MatInputModule, MatIconModule,
    CommonModule, MatTableModule, MatLabel, FormsModule, LoaderComponent
  ],
  templateUrl: './purpose.component.html',
  styleUrl: './purpose.component.css'
})
export class PurposeComponent implements OnDestroy {
  loader = inject(LoaderService);
  isLoading = computed(() => this.loader.loading());

  searchTerm: string = '';
  displayedColumns: string[] = ['Sl.No', 'name', 'Action'];
  dataSource = new MatTableDataSource<MaPurpose>();

  currentPage = 1;
  pageSize = 50;
  totalCount = 0;
  allDataLoaded = false;
  private searchSubject = new Subject<string>();

  constructor(
    private dialog: MatDialog,
    private purposeService: PurposeService,
    private snackBar: SnackbarService
  ) { }

  ngOnInit() {
    this.getMaPurposeDataFromDb(true);

    // Setup debounce for search
    this.searchSubject
      .pipe(
        debounceTime(1000)
      )
      .subscribe(() => {
        this.onSearch();
      });
  }

  ngOnDestroy() {
    this.searchSubject.complete();
  }

  inputSearch(): void {
    if (this.searchTerm.trim() === '') {
      this.onSearch();
    } else {
      this.searchSubject.next(this.searchTerm);
    }
  }

  onSearch(): void {
    this.getMaPurposeDataFromDb(true);
  }

  clearSearch(): void {
    this.searchTerm = '';
    this.getMaPurposeDataFromDb(true);
  }

  onManualScroll(): void {
    const scrollContainer = document.querySelector('.table-container');
    if (scrollContainer) {
      const scrollPosition = scrollContainer.scrollTop + scrollContainer.clientHeight;
      const scrollHeight = scrollContainer.scrollHeight;

      if (
        scrollPosition >= scrollHeight - 10 &&
        !this.loader.loading() &&
        !this.allDataLoaded
      ) {
        this.getMaPurposeDataFromDb();
      }
    }
  }

  getMaPurposeDataFromDb(reset = false): void {
    if (reset) {
      this.currentPage = 1;
      this.allDataLoaded = false;
      this.dataSource.data = [];
      this.totalCount = 0;
    }

    const body = {
      page: this.currentPage,
      page_size: this.pageSize,
      query: this.searchTerm.trim(),
    };

    this.loader.show();

    this.purposeService.purposeDataFromDb(body).subscribe({
      next: (response: { data: MaPurpose[]; total_count: number }) => {
        const newData = response.data;
        this.totalCount = response.total_count;

        this.dataSource.data = [...this.dataSource.data, ...newData];

        if (this.dataSource.data.length >= this.totalCount) {
          this.allDataLoaded = true;
        }

        this.currentPage++;
        this.loader.hide();
      },
      error: () => {
        this.snackBar.showError("Something went wrong. Please try again later.");
        this.loader.hide();
      }
    });
  }

  openAddPurposeDialog(): void {
    const dialogConfig = new MatDialogConfig();
    dialogConfig.position = { right: '0' };
    dialogConfig.height = '100%';
    dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];

    const dialogRef = this.dialog.open(CreatePurposeComponent, dialogConfig);
    dialogRef.afterClosed().subscribe((result) => {
      if (result === 'refresh') {
        this.getMaPurposeDataFromDb(true);
      }
    });
  }

  openEditPurposeDialog(rowData: MaPurpose): void {
    const dialogConfig = new MatDialogConfig();
    dialogConfig.position = { right: '0' };
    dialogConfig.height = '100%';
    dialogConfig.data = { rowData };
    dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];

    const dialogRef = this.dialog.open(CreatePurposeComponent, dialogConfig);
    dialogRef.afterClosed().subscribe((result) => {
      if (result === 'refresh') {
        this.getMaPurposeDataFromDb(true);
      }
    });
  }
}
